library(shiny)
library(reactable)
library(dplyr)


# To transfer the needed documents, use the following command in the terminal:
#shinylive::export(appdir = "../ruraldata/", destdir = "docs")

cari_ED_jenks_min <- readRDS("cari_ED_jenks_min.rds")
cari_ED_jenks_dis <- readRDS("cari_ED_jenks_dis.rds")

ui <- fluidPage(
  h2("ED Accessibility Table", align = "centre"),

  selectInput("metric", "Select Metric:",
              choices = c("Minutes", "Distance")),

  reactableOutput("table")
)

server <- function(input, output) {

  selected_data <- reactive({
    if (input$metric == "Minutes") {
      cari_ED_jenks_min
    } else {
      cari_ED_jenks_dis
    }
  })

  output$table <- renderReactable({

    df <- selected_data()
    df <- df %>%
      mutate(Category = case_when(
        Indicator == "Total Population" ~ "Population",
        Indicator %in% c("Males", "Females") ~ "Sex",
        Indicator %in% c("<15 years", "15-64 years", "65+") ~ "Age Structure",
        Indicator %in% c("Less than HS", "High School", 
                         "Diploma", "University") ~ "Education",
        Indicator %in% c("Immigrants", "Non-Immigrants", 
                         "Imm. (<10yrs)") ~ "Immigration",
        Indicator %in% c("Indigenous", "Non-Indigenous") ~ "Indigenous Identity",
        Indicator %in% c("Material", "Social") ~ "Deprivation",
        Indicator %in% c("Instability", "Dependency", 
                         "Ethnic Conc.", "Deprivation") ~ "Marginalization",

        TRUE ~ "Other"
      )) %>%
      select(Category, Indicator, cat1, cat2, cat3, cat4, cat5)

    reactable(
      df,
      defaultPageSize = nrow(df),
      #groupBy = "parent", defaultExpanded = TRUE, onClick = "expand",
      #bordered = TRUE, striped = TRUE, highlight = TRUE,
      compact = TRUE, height = "auto", outlined = TRUE,
      columns = list(
        Category = colDef(name = "Category",
                        style = JS("function(rowInfo, column, state) {
        const firstSorted = state.sorted[0]
        // Merge cells if unsorted or sorting by school
        if (!firstSorted || firstSorted.id === 'Category') {
          const prevRow = state.pageRows[rowInfo.viewIndex - 1]
          if (prevRow && rowInfo.values['Category'] === prevRow['Category']) {
            return { visibility: 'hidden' }
          }
        }
      }")),
        Indicator = colDef(name = "Indicator"),
        cat1 = colDef(name = "Easily Accessible", cell = function(value) {
          #if (value > 100) {formatted_value <- sprintf("%.0f", value) } 
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat2 = colDef(name = "Accessible", cell = function(value) {
          #if (value > 100) {formatted_value <- sprintf("%.0f", value) } 
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat3 = colDef(name = "Less Accessible", cell = function(value) {
          #if (value > 100) {formatted_value <- sprintf("%.0f", value) } 
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat4 = colDef(name = "Remote", cell = function(value) {
          #if (value > 100) {formatted_value <- sprintf("%.0f", value) } 
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) }),
        cat5 = colDef(name = "More Remote", cell = function(value) {
          #if (value > 100) {formatted_value <- sprintf("%.0f", value) } 
          if (value > 100) {formatted_value <- format(value, big.mark = ",") } 
          else {formatted_value <- sprintf("%.2f%%", value) }
          return(formatted_value) })
      ),
      ,
      rowStyle = JS("function(rowInfo) {
    if (rowInfo.level > 0) {
      return { background: '#eee', borderLeft: '2px solid #ffa62d' }
    } else {
      return { borderLeft: '2px solid transparent' }
    }
  }")
    )
  })
}

shinyApp(ui, server)
